import{c as n}from"./app.8935f5f1.js";const s={},a=n('<h4 id="vue-自定义指令有全局注册和局部注册两种方式。" tabindex="-1"><a class="header-anchor" href="#vue-自定义指令有全局注册和局部注册两种方式。" aria-hidden="true">#</a> Vue 自定义指令有全局注册和局部注册两种方式。</h4><ol><li>通过 <code>Vue.directive( id, [definition] )</code> 方式注册全局指令。然后在入口文件中进行 <code>Vue.use() </code>调用。</li></ol><h3 id="注册指令" tabindex="-1"><a class="header-anchor" href="#注册指令" aria-hidden="true">#</a> 注册指令</h3><ul><li>批量注册指令，新建 <code>directives/index.js</code> 文件</li></ul><div class="language-javascript ext-js"><pre class="language-javascript"><code><span class="token keyword">import</span> copy <span class="token keyword">from</span> <span class="token string">&#39;./copy&#39;</span>\n<span class="token keyword">import</span> longpress <span class="token keyword">from</span> <span class="token string">&#39;./longpress&#39;</span>\n<span class="token comment">// 自定义指令</span>\n<span class="token keyword">const</span> directives <span class="token operator">=</span> <span class="token punctuation">{</span>\n  copy<span class="token punctuation">,</span>\n  longpress<span class="token punctuation">,</span>\n<span class="token punctuation">}</span>\n\n<span class="token keyword">export</span> <span class="token keyword">default</span> <span class="token punctuation">{</span>\n  <span class="token function">install</span><span class="token punctuation">(</span><span class="token parameter">Vue</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>\n    Object<span class="token punctuation">.</span><span class="token function">keys</span><span class="token punctuation">(</span>directives<span class="token punctuation">)</span><span class="token punctuation">.</span><span class="token function">forEach</span><span class="token punctuation">(</span><span class="token punctuation">(</span><span class="token parameter">key</span><span class="token punctuation">)</span> <span class="token operator">=&gt;</span> <span class="token punctuation">{</span>\n      Vue<span class="token punctuation">.</span><span class="token function">directive</span><span class="token punctuation">(</span>key<span class="token punctuation">,</span> directives<span class="token punctuation">[</span>key<span class="token punctuation">]</span><span class="token punctuation">)</span>\n    <span class="token punctuation">}</span><span class="token punctuation">)</span>\n  <span class="token punctuation">}</span><span class="token punctuation">,</span>\n<span class="token punctuation">}</span>\n</code></pre></div><ul><li>在 <code>main.js</code> 引入并调用</li></ul><div class="language-javascript ext-js"><pre class="language-javascript"><code><span class="token keyword">import</span> Vue <span class="token keyword">from</span> <span class="token string">&#39;vue&#39;</span>\n<span class="token keyword">import</span> Directives <span class="token keyword">from</span> <span class="token string">&#39;./JS/directives&#39;</span>\nVue<span class="token punctuation">.</span><span class="token function">use</span><span class="token punctuation">(</span>Directives<span class="token punctuation">)</span>\n</code></pre></div><p>指令定义函数提供了几个钩子函数（可选）：</p><ul><li>bind: 只调用一次，指令第一次绑定到元素时调用，可以定义一个在绑定时执行一次的初始化动作。</li><li>inserted: 被绑定元素插入父节点时调用（父节点存在即可调用，不必存在于 document 中）。</li><li>update: 被绑定元素所在的模板更新时调用，而不论绑定值是否变化。通过比较更新前后的绑定值。</li><li>componentUpdated: 被绑定元素所在模板完成一次更新周期时调用。</li><li>unbind: 只调用一次， 指令与元素解绑时调用。</li></ul>',9);s.render=function(n,s){return a};export{s as default};
